#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    /* Check turbidity timeout */
    if (controller->has_valid_turbidity) {
        if ((now_ms < controller->last_turbidity_ms) || 
            (now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
            return true;
        }
    }

    /* Check level timeout */
    if (controller->has_valid_level) {
        if ((now_ms < controller->last_level_ms) || 
            (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
            return true;
        }
    }

    return false;
}

static void controller_handle_turbidity(controller_t *controller, int turbidity_ntu, uint32_t now_ms)
{
    controller->has_valid_turbidity = true;
    controller->last_turbidity_ntu = turbidity_ntu;
    controller->last_turbidity_ms = now_ms;

    /* Handle based on current state */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* If both sensors are now valid and level < 15, go to COMPLETE */
        if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            controller->filter_on = false;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
        }
        /* Otherwise stay in SAFE_IDLE - handled by caller */
        break;

    case CONTROLLER_STATE_FILTERING:
        if (turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            controller->clear_streak_count++;
        } else {
            controller->clear_streak_count = 0;
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        /* If TURB > 40 during settling, return to FILTERING */
        if (turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
        }
        /* If TURB <= 35, just update the last turbidity - no streak increment needed */
        break;

    case CONTROLLER_STATE_DRAINING:
        /* If level drops below threshold, go to COMPLETE */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            controller->filter_on = false;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
        }
        /* If TURB > 50 and LEVEL >= 40, return to FILTERING */
        else if (turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU && 
                 controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        /* Stay in COMPLETE if level < 15 */
        break;
    }
}

static void controller_handle_level(controller_t *controller, int level, uint32_t now_ms)
{
    controller->has_valid_level = true;
    controller->last_level = level;
    controller->last_level_ms = now_ms;

    /* If level drops below COMPLETE threshold and both sensors are valid, go to COMPLETE */
    if (level < CONTROLLER_COMPLETE_LEVEL && controller->has_valid_turbidity) {
        controller->state = CONTROLLER_STATE_COMPLETE;
        controller->filter_on = false;
        controller->drain_open = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
    } else if (controller->state == CONTROLLER_STATE_COMPLETE && level >= CONTROLLER_COMPLETE_LEVEL) {
        /* If we're in COMPLETE and level rises, go back to SAFE_IDLE */
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
        controller->filter_on = false;
        controller->drain_open = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
    }
}

static void controller_try_transition_to_settling(controller_t *controller)
{
    /* Can only transition to SETTLING from FILTERING with clear streak = 3 and LEVEL >= 40 */
    if (controller->state == CONTROLLER_STATE_FILTERING &&
        controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        controller->state = CONTROLLER_STATE_SETTLING;
        controller->filter_on = false;
        controller->drain_open = false;
        controller->settling_started_ms = controller->last_turbidity_ms;
    }
}

static void controller_try_transition_to_draining(controller_t *controller, uint32_t now_ms)
{
    /* Can transition to DRAINING from SETTLING if:
     * - Settling has lasted at least 400ms
     * - Latest TURB <= 35
     * - LEVEL >= 40
     */
    if (controller->state == CONTROLLER_STATE_SETTLING &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
        controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {

        uint32_t settling_elapsed = now_ms - controller->settling_started_ms;
        if (settling_elapsed >= CONTROLLER_SETTLING_MS) {
            controller->state = CONTROLLER_STATE_DRAINING;
            controller->filter_on = false;
            controller->drain_open = true;
        }
    }
}

static void controller_try_start_filtering(controller_t *controller)
{
    /* Start filtering if:
     * - Both sensors are valid
     * - LEVEL >= 40
     * - TURB > 35 (cloudy)
     */
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE &&
        controller->has_valid_turbidity &&
        controller->has_valid_level &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
        controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
        controller->state = CONTROLLER_STATE_FILTERING;
        controller->filter_on = true;
        controller->drain_open = false;
        controller->clear_streak_count = 0;
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller_handle_turbidity(controller, input.turbidity_ntu, input.now_ms);
        break;

    case CONTROLLER_INPUT_LEVEL:
        controller_handle_level(controller, input.level, input.now_ms);
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* Check for sensor timeout on idle steps */
        if (controller_check_sensor_timeout(controller, input.now_ms)) {
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
            output.timed_out = true;
        }
        break;
    }

    /* Apply state transitions based on current conditions */
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
        controller_try_start_filtering(controller);
    } else if (controller->state == CONTROLLER_STATE_FILTERING) {
        controller_try_transition_to_settling(controller);
    } else if (controller->state == CONTROLLER_STATE_SETTLING) {
        controller_try_transition_to_draining(controller, input.now_ms);
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

